static int em_check_pdv_pdu_mismatch(double pdu_len_val, double pdv_len_val) {
    uint32_t pdu_len = (uint32_t)pdu_len_val;
    uint32_t pdv_len = (uint32_t)pdv_len_val;
    /* For single-PDV P-DATA-TF: pdu_len = pdv_item_length_field(4) + pdv_content(pdv_len)
       So pdu_len should equal pdv_len + 4 */
    if (pdu_len != pdv_len + 4)
        return 1;
    return 0;
}
